'Windows-8-6.2.9200'

I don't know netlink that well, but the Linux kernel might not let us control what addresses are primary or secondary.

[net/ipv4/devinet.c](https://github.com/torvalds/linux/blob/master/net/ipv4/devinet.c#L440)

``` {.c}
static int __inet_insert_ifa(struct in_ifaddr *ifa, struct nlmsghdr *nlh,
			     u32 portid)
{
	struct in_device *in_dev = ifa->ifa_dev;
	struct in_ifaddr *ifa1, **ifap, **last_primary;

	ASSERT_RTNL();

	if (!ifa->ifa_local) {
		inet_free_ifa(ifa);
		return 0;
	}

	ifa->ifa_flags &= ~IFA_F_SECONDARY;
	last_primary = &in_dev->ifa_list;

	for (ifap = &in_dev->ifa_list; (ifa1 = *ifap) != NULL;
	     ifap = &ifa1->ifa_next) {
		if (!(ifa1->ifa_flags & IFA_F_SECONDARY) &&
		    ifa->ifa_scope <= ifa1->ifa_scope)
			last_primary = &ifa1->ifa_next;
		if (ifa1->ifa_mask == ifa->ifa_mask &&
		    inet_ifa_match(ifa1->ifa_address, ifa)) {
			if (ifa1->ifa_local == ifa->ifa_local) {
				inet_free_ifa(ifa);
				return -EEXIST;
			}
			if (ifa1->ifa_scope != ifa->ifa_scope) {
				inet_free_ifa(ifa);
				return -EINVAL;
			}
			ifa->ifa_flags |= IFA_F_SECONDARY;
		}
	}
```

[Here is a thread about adding such functionality to the kernel.](https://groups.google.com/forum/#!topic/fa.linux.kernel/qiF29jkCeeQ)

If we can't control primary and secondary addresses, then we would need to remove and add addresses so the `primary=True` parameter is honored. I also don't know pyroute2 very well, but adding or removing addresses seems tricky to implement (e.g., might cause unrelated IP addresses to disappear and break connections).

Choosing the set of primary addresses might not cover all use cases. Our use case is one example: We have two addresses X and Y on one interface attached to network X/24. We want devices on network X/24 to receive ICMP replies from X and other remote devices (not in X/24) to receive replies from Y. To do this, we need two primary addresses and need to add Y before X.

[net/ipv4/devinet.c](https://github.com/torvalds/linux/blob/master/net/ipv4/devinet.c#L1196)

``` {.c}
__be32 inet_select_addr(const struct net_device *dev, __be32 dst, int scope)
{
	__be32 addr = 0;
	struct in_device *in_dev;
	struct net *net = dev_net(dev);
	int master_idx;

	rcu_read_lock();
	in_dev = __in_dev_get_rcu(dev);
	if (!in_dev)
		goto no_in_dev;

	for_primary_ifa(in_dev) {
		if (ifa->ifa_scope > scope)
			continue;
		if (!dst || inet_ifa_match(dst, ifa)) {
			addr = ifa->ifa_local;
			break;
		}
		if (!addr)
			addr = ifa->ifa_local;
	} endfor_ifa(in_dev);
```

