Here is code that shows the problem. While experimenting, I found out that the problem only happens if I create multiple top-level schema objects. If I reuse the same top-level schema object, everything works as expected.

Chris



from marshmallow import Schema, fields, pre_load

list1 = {
    "users" : [
        {
            "name" : "John",
            "number" : 23
        },
        {
            "name" : "Joe",
            "number" : 24
        }
    ]
}


list2 = {
    "users" : [
        {
            "name" : "Jane",
            "number" : 2
        },
    ]
}

class NestedSchema(Schema):
    name = fields.Str()
    number = fields.Integer()

    @pre_load
    def print_context(self, data, many=False):
        print 'NestedSchema context: ' + str(self.context)

class MySchema(Schema):
    users = fields.List(fields.Nested(NestedSchema))

    @pre_load
    def print_context(self, data, many=False):
